`timescale 1ns/1ps
// Functional testbench for bnn_core.v.
// Feeds 7 REAL MNIST test-set images (not synthetic/hand-drawn -- pulled
// straight from the standard mnist.pkl.gz test split via
// verify_and_export.py) through the binarized network and checks the
// predicted digit against the same pure-integer XNOR+popcount reference
// model computed in Python (which itself was checked to reproduce the
// trained float model's accuracy -- see verify_and_export.py). 6 of the 7
// are cases the model gets right (one per several digit classes); the 7th
// is a case it gets WRONG (predicts 6, true label is 2) included on
// purpose so the testbench also exercises/confirms that misclassification
// path instead of only ever checking "happy path" correct answers.
module tb_bnn_core;

reg clk = 0;
reg rst_n;
reg start;
reg [783:0] image_in;

wire done;
wire [3:0] digit_out;

bnn_core dut (
    .clk (clk), .rst_n (rst_n),
    .start (start), .image_in (image_in),
    .done (done), .digit_out (digit_out)
);

always #5 clk = ~clk;

integer errors = 0;
integer i;

// test images: real MNIST test-set samples (idx into the standard test
// split), bit[y*28+x] = pixel(y,x), from bnn_test_images.txt
reg [783:0] test_img [0:6];
reg  [3:0]  expect_pred [0:6];
reg  [3:0]  true_label [0:6];

initial begin
    // idx=0  true_label=7  hw_pred=7
    test_img[0] = 784';
    expect_pred[0] = 4'd7; true_label[0] = 4'd7;

    // idx=2  true_label=1  hw_pred=1
    test_img[1] = 784';
    expect_pred[1] = 4'd1; true_label[1] = 4'd1;

    // idx=3  true_label=0  hw_pred=0
    test_img[2] = 784';
    expect_pred[2] = 4'd0; true_label[2] = 4'd0;

    // idx=4  true_label=4  hw_pred=4
    test_img[3] = 784';
    expect_pred[3] = 4'd4; true_label[3] = 4'd4;

    // idx=12 true_label=9  hw_pred=9
    test_img[4] = 784';
    expect_pred[4] = 4'd9; true_label[4] = 4'd9;

    // idx=18 true_label=3  hw_pred=3
    test_img[5] = 784';
    expect_pred[5] = 4'd3; true_label[5] = 4'd3;

    // idx=1  true_label=2  hw_pred=6  <-- deliberately a MISCLASSIFIED case
    test_img[6] = 784';
    expect_pred[6] = 4'd6; true_label[6] = 4'd2;
end

task do_reset;
begin
    rst_n = 0;
    start = 0;
    image_in = 784'd0;
    repeat (4) @(posedge clk);
    rst_n = 1;
    repeat (2) @(posedge clk);
end
endtask

task classify_one(input integer idx);
begin
    image_in = test_img[idx];
    @(negedge clk); start = 1'b1;
    @(negedge clk); start = 1'b0;
    // bnn_core takes ~1040 cycles per image (676+169+144+36+10 stage steps);
    // wait generously for `done`.
    wait (done == 1'b1);
    $display("img[%0d]: true_label=%0d expected_hw_pred=%0d got=%0d",
              idx, true_label[idx], expect_pred[idx], digit_out);
    if (digit_out !== expect_pred[idx]) begin
        $display("FAIL: img[%0d] expected %0d, got %0d", idx, expect_pred[idx], digit_out);
        errors = errors + 1;
    end
    @(posedge clk);
end
endtask

initial begin
    do_reset;

    for (i = 0; i < 7; i = i + 1)
        classify_one(i);

    if (errors == 0)
        $display("ALL TESTS PASSED");
    else
        $display("%0d TEST(S) FAILED", errors);

    $finish;
end

initial begin
    #2000000;   // generous timeout for ~7*1040 cycles at 10ns period
    $display("TIMEOUT");
    $finish;
end

endmodule
